"use client";

import { useEffect, useMemo, useState } from "react";
import { X } from "lucide-react";
import toast from "react-hot-toast";
import { useAuth } from "@/app/(auth)/context/AuthContext";
import vendorRepository from "../services/VendorRepository";

export default function VendorPaymentDialog({open,onClose,companyId,vendors,projects,initialVendor}){
 const {currentUser}=useAuth();const [saving,setSaving]=useState(false);const [form,setForm]=useState({vendorId:"",projectId:"",amount:"",date:new Date().toISOString().slice(0,10),referenceNumber:"",remarks:"",managerApproved:false});
 useEffect(()=>{if(open)setForm((value)=>({...value,vendorId:initialVendor?.id||"",projectId:"",amount:"",referenceNumber:"",remarks:"",managerApproved:false}));},[open,initialVendor]);
 const available=useMemo(()=>projects.filter((project)=>(project.vendors||[]).some((item)=>item.vendorId===form.vendorId||item.firestoreId===form.vendorId)),[projects,form.vendorId]);
 const assignment=available.find((item)=>item.id===form.projectId)?.vendors?.find((item)=>item.vendorId===form.vendorId||item.firestoreId===form.vendorId);const allocated=Number(assignment?.allocatedAmount||0),paid=Number(assignment?.paidAmount||0),next=paid+Number(form.amount||0),exceeds=next>allocated;
 if(!open)return null;const update=(key,value)=>setForm((current)=>({...current,[key]:value}));
 const submit=async(event)=>{event.preventDefault();setSaving(true);try{await vendorRepository.createPayment(companyId,form,currentUser);toast.success("Vendor payment recorded.");onClose();}catch(error){console.error(error);toast.error(error.message||"Payment failed.");}finally{setSaving(false);}};
 const input="mt-1.5 h-11 w-full rounded-xl border border-slate-200 bg-white px-3 text-sm";
 return <div className="fixed inset-0 z-[90] grid place-items-center bg-slate-900/30 p-4 backdrop-blur-sm"><form onSubmit={submit} className="w-full max-w-xl rounded-3xl bg-[#F9FAFC] shadow-2xl"><header className="flex items-center justify-between border-b bg-white p-5"><div><h2 className="text-xl font-bold">Vendor payment</h2><p className="text-xs text-slate-500">Payments update vendor and project balances automatically</p></div><button type="button" onClick={onClose}><X/></button></header><div className="space-y-4 p-5"><label className="block text-xs font-bold">Vendor<select required value={form.vendorId} onChange={(e)=>{update("vendorId",e.target.value);update("projectId","");}} className={input}><option value="">Select vendor</option>{vendors.map((item)=><option key={item.id} value={item.id}>{item.companyName||item.vendorName}</option>)}</select></label><label className="block text-xs font-bold">Assigned project<select required value={form.projectId} onChange={(e)=>update("projectId",e.target.value)} className={input}><option value="">Select project</option>{available.map((item)=><option key={item.id} value={item.id}>{item.projectName}</option>)}</select></label>{assignment&&<div className="grid grid-cols-3 gap-2 rounded-2xl bg-white p-4 text-center text-xs"><span>Allocated<strong className="block text-sm">₹{allocated.toLocaleString("en-IN")}</strong></span><span>Paid<strong className="block text-sm">₹{paid.toLocaleString("en-IN")}</strong></span><span>Remaining<strong className="block text-sm">₹{Math.max(0,allocated-paid).toLocaleString("en-IN")}</strong></span></div>}<div className="grid gap-4 sm:grid-cols-2"><label className="block text-xs font-bold">Amount<input required min="0.01" step="0.01" type="number" value={form.amount} onChange={(e)=>update("amount",e.target.value)} className={input}/></label><label className="block text-xs font-bold">Date<input required type="date" value={form.date} onChange={(e)=>update("date",e.target.value)} className={input}/></label><label className="block text-xs font-bold">Reference<input value={form.referenceNumber} onChange={(e)=>update("referenceNumber",e.target.value)} className={input}/></label><label className="block text-xs font-bold">Remarks<input value={form.remarks} onChange={(e)=>update("remarks",e.target.value)} className={input}/></label></div>{exceeds&&<label className="flex gap-3 rounded-2xl border border-red-200 bg-red-50 p-4 text-sm font-semibold text-red-700"><input type="checkbox" checked={form.managerApproved} onChange={(e)=>update("managerApproved",e.target.checked)}/><span>This payment exceeds allocation by ₹{(next-allocated).toLocaleString("en-IN")}. Confirm manager approval to continue.</span></label>}</div><footer className="flex justify-end gap-3 border-t bg-white p-5"><button type="button" onClick={onClose} className="rounded-xl border px-5 py-2.5 font-bold">Cancel</button><button disabled={saving||exceeds&&!form.managerApproved} className="rounded-xl bg-blue-600 px-5 py-2.5 font-bold text-white disabled:opacity-40">{saving?"Processing...":"Create payment"}</button></footer></form></div>;
}
